example.code:
concurrency:
  group: ${{ github.workflow }}-${{ github.ref }}
  cancel-in-progress: true

concurrency:
  group: deploy-${{ inputs.environment || 'staging' }}
  cancel-in-progress: false

# .github/workflows/ci.yml name: CI on: push: branches: [main, develop] pull_request: branches: [main] permissions: contents: read checks: write concurrency: group: ci-${{ github.ref }} cancel-in-progress: true jobs: lint: name: Lint runs-on: ubuntu-latest steps: - uses: actions/checkout@v4 - uses: actions/setup-node@v4 with: { node-version: '20', cache: 'npm' } - run: npm ci - run: npm run lint - run: npm run format:check
test: name: Test (${{ matrix.os }}, Node ${{ matrix.node }}) runs-on: ${{ matrix.os }} needs: lint strategy: fail-fast: false matrix: os: [ubuntu-latest, windows-latest] node: [18, 20, 22] exclude: - os: windows-latest node: 18 steps: - uses: actions/checkout@v4 - uses: actions/setup-node@v4 with: { node-version: '${{ matrix.node }}', cache: 'npm' } - run: npm ci - run: npm test -- --coverage - if: matrix.os == 'ubuntu-latest' && matrix.node == '20' uses: codecov/codecov-action@v4 with: token: ${{ secrets.CODECOV_TOKEN }}
build: name: Build runs-on: ubuntu-latest needs: test steps: - uses: actions/checkout@v4 - uses: actions/setup-node@v4 with: { node-version: '20', cache: 'npm' } - run: npm ci && npm run build - uses: actions/upload-artifact@v4 with: name: build path: dist/ retention-days: 7

# .github/workflows/scheduled.yml name: Scheduled Tasks on: schedule: - cron: '0 2 * * *' # Daily at 02:00 UTC (low traffic) workflow_dispatch: # Manual trigger for incidents jobs: cleanup: name: Cleanup Old Artifacts runs-on: ubuntu-latest steps: - uses: c-hive/gha-remove-artifacts@v1 with: { age: '30 days', skip-recent: 5 }
security-scan: name: Security Scan runs-on: ubuntu-latest steps: - uses: actions/checkout@v4 - uses: aquasecurity/trivy-action@master with: scan-type: 'fs' scan-ref: '.' format: 'sarif' output: 'trivy-results.sarif' - uses: github/codeql-action/upload-sarif@v3 with: { sarif_file: 'trivy-results.sarif' }
dependency-update: name: Dependency Audit runs-on: ubuntu-latest steps: - uses: actions/checkout@v4 - uses: actions/setup-node@v4 with: { node-version: '20' } - run: npm outdated || true - run: npm audit --audit-level=high
